#include <iostream>

// Passage par valeur (Copie)
void incrementerCopie(int x) { x++; }

// Passage par référence (Alias direct)
void incrementerRef(int& x) { x++; }

int main() {
    int compteur = 10;
    incrementerCopie(compteur); // compteur vaut toujours 10
    incrementerRef(compteur);   // compteur vaut maintenant 11
    return 0;
}

