poo_polymorphism_02.complete:
#include <iostream>

class Animal {
public:
    // Destructeur virtuel indispensable pour l'héritage !
    virtual ~Animal() = default;
    virtual void crier() const { std::cout << "...\n"; }
};

class Chien : public Animal {
public:
    void crier() const override { std::cout << "Wouf!\n"; }
};

int main() {
    Animal* monAnimal = new Chien();
    monAnimal->crier(); // Appelle Wouf! grâce au polymorphisme
    delete monAnimal;
    return 0;
}

