#include <iostream>
#include <stdexcept>

int main() {
    try {
        int age = -5;
        if (age < 0) {
            throw std::invalid_argument("L'âge ne peut pas être négatif.");
        }
    } catch (const std::invalid_argument& e) {
        std::cerr << "Erreur argument : " << e.what() << "\n";
    } catch (const std::exception& e) {
        std::cerr << "Erreur générale : " << e.what() << "\n";
    }
    // C++ n'a pas de bloc 'finally' natif !
    return 0;
}

