conc_async_02.complete:
#include <iostream>
#include <future>
#include <thread>

int appelerServeur() {
    std::this_thread::sleep_for(std::chrono::milliseconds(500));
    return 200;
}

int main() {
    std::cout << "Lancement...\n";
    std::future<int> resultatFuture = std::async(std::launch::async, appelerServeur);
    std::cout << "Le thread principal continue...\n";

    int codeStatut = resultatFuture.get();
    std::cout << "Réponse reçue : " << codeStatut << "\n";
    return 0; 
}

